15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const FIRST_INSURANCE_MULTIPLIER = 1.1;
23	const PROCESSING_FEE = 5;
24	const ROUNDING_PRECISION = 6;
25	
26	const quotePremium = (items: Item[]): number => {
27	  let total = 0;
28	  for (const item of items) {
29	    const base = BASE_PREMIUM[item.type];
30	    total += base * FIRST_INSURANCE_MULTIPLIER;
31	  }
32	  const totalWithFee = total + PROCESSING_FEE;
33	  return Math.ceil(Number(totalWithFee.toFixed(ROUNDING_PRECISION)));
34	};
35	
36	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
37	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
38	  return { results };
39	};
